// src/pages/Payroll/PayrollPage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  CreditCard, DollarSign, AlertTriangle, FileText,
  Play, CheckCircle, Download, Plus, RefreshCw,
  TrendingUp, Users, Zap, Settings, ShieldCheck,
  Calculator
} from 'lucide-react';
import toast from 'react-hot-toast';
import { payrollAPI } from '../../api/services';
import { Badge, SkeletonCard, SkeletonTable, Modal, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';

/* ── Dashboard KPI card ── */
function PayKPI({ icon: Icon, label, value, color, sub }) {
  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div className="stat-card-icon" style={{ background: `${color}22` }}>
        <Icon size={20} style={{ color }} />
      </div>
      <div className="stat-card-value">{value ?? '—'}</div>
      <div className="stat-card-label">{label}</div>
      {sub && <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: 3 }}>{sub}</div>}
    </div>
  );
}

/* ── Payslip viewer ── */
function PayslipModal({ payslip, onClose }) {
  if (!payslip) return null;

  const financialData = payslip?.Entry || payslip || {};
  const runData = payslip?.PayrollRun || payslip || {};

  const startDate = runData?.PeriodStartDate || runData?.payPeriodStart || payslip?.IssueDate;
  const endDate = runData?.PeriodEndDate || runData?.payPeriodEnd;
  const status = payslip?.Status || payslip?.status || 'Finalized';

  const netPay = financialData?.NetPay || financialData?.netPay || 0;
  const grossPay = financialData?.TotalEarnings || financialData?.totalEarnings || 0;
  const totalDeductions = financialData?.TotalDeductions || financialData?.totalDeductions || 0;

  const lines = financialData?.Lines || [];
  const earningsLines = lines.filter(l => Number(l.Amount || l.amount) > 0);
  const deductionLines = lines.filter(l => Number(l.Amount || l.amount) < 0);

  const fmt = (v) => Number(v).toLocaleString('en-US', { style: 'currency', currency: 'EGP' });

  return (
    <Modal open={!!payslip} onClose={onClose} title="Payslip Details" size="modal-lg">
      <div style={{
        background: 'var(--bg-base)', border: '1px solid var(--border)',
        borderRadius: 'var(--radius-lg)', padding: 24, marginBottom: 16,
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 20 }}>
          <div>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem', fontWeight: 700 }}>Official Payslip</div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
              Period: {startDate ? `${new Date(startDate).toLocaleDateString()} – ${endDate ? new Date(endDate).toLocaleDateString() : 'Present'}` : '—'}
            </div>
          </div>
          <div style={{ textAlign: 'right' }}>
            <Badge status={status}>{status}</Badge>
          </div>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--green)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 8 }}>Earnings Breakdown</div>
            {earningsLines.map((line, idx) => (
              <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)' }}>
                <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{line.Description || line.description || 'Earning'}</span>
                <span style={{ fontSize: '0.82rem', color: 'var(--text-primary)' }}>{fmt(Math.abs(line.Amount || line.amount))}</span>
              </div>
            ))}
            <div style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)', fontWeight: 700, marginTop: 8 }}>
              <span style={{ fontSize: '0.82rem', color: 'var(--text-primary)' }}>Total Gross Pay</span>
              <span style={{ fontSize: '0.82rem', color: 'var(--green)' }}>{fmt(grossPay)}</span>
            </div>
          </div>

          <div>
            <div style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--red)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 8 }}>Deductions & Penalties</div>
            {deductionLines.length === 0 ? (
              <div style={{ fontSize: '0.82rem', color: 'var(--text-muted)', fontStyle: 'italic' }}>No deductions this period.</div>
            ) : (
              deductionLines.map((line, idx) => (
                <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)' }}>
                  <span style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>{line.Description || line.description || 'Deduction'}</span>
                  <span style={{ fontSize: '0.82rem', color: 'var(--text-primary)' }}>{fmt(Math.abs(line.Amount || line.amount))}</span>
                </div>
              ))
            )}
            <div style={{ display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid var(--border-light)', fontWeight: 700, marginTop: 8 }}>
              <span style={{ fontSize: '0.82rem', color: 'var(--text-primary)' }}>Total Deductions</span>
              <span style={{ fontSize: '0.82rem', color: 'var(--red)' }}>{fmt(totalDeductions)}</span>
            </div>
          </div>
        </div>

        <div style={{ marginTop: 16, padding: '14px 16px', background: 'var(--gold-glow)', border: '1px solid rgba(240,180,41,0.3)', borderRadius: 'var(--radius-md)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontFamily: 'var(--font-display)', fontWeight: 600 }}>FINAL NET PAY</span>
          <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 700, color: 'var(--gold)' }}>{fmt(netPay)}</span>
        </div>
      </div>
    </Modal>
  );
}

/* ── Main Page Component ── */
export default function PayrollPage() {
  const { user } = useAuth();
  const isPayroll = ['Payroll', 'HR', 'Admin'].includes(user?.role);

  const [tab, setTab] = useState('dashboard');
  const [dashboard, setDash] = useState(null);
  const [runs, setRuns] = useState([]);
  const [myPayslips, setMySlips] = useState([]);
  const [exceptions, setExcept] = useState([]);
  const [selectedSlip, setSlip] = useState(null);
  const [loadDash, setLoadDash] = useState(true);
  const [loadRuns, setLoadRuns] = useState(true);
  const [createRunModal, setCreateRunModal] = useState(false);
  const [saving, setSaving] = useState(false);

  const [runForm, setRunForm] = useState({ PolicyID: 1, PeriodStartDate: '', PeriodEndDate: '', CutoffDate: '', PaymentDate: '' });

  const load = useCallback(() => {
    const extract = (res) => {
      let payload = res;
      if (payload && payload.data !== undefined) payload = payload.data;
      if (payload && payload.success !== undefined && payload.data !== undefined) payload = payload.data;
      return payload || null;
    };

    if (isPayroll) {
      payrollAPI.getDashboard().then((res) => { setDash(extract(res)); setLoadDash(false); }).catch(() => setLoadDash(false));
      payrollAPI.listRuns({ limit: 10 }).then((res) => {
        const payload = extract(res);
        setRuns(Array.isArray(payload) ? payload : (payload?.runs || []));
        setLoadRuns(false);
      }).catch(() => setLoadRuns(false));
      payrollAPI.listExceptions().then((res) => {
        const payload = extract(res);
        setExcept(Array.isArray(payload) ? payload : (payload?.exceptions || []));
      }).catch(() => { });
    } else { setLoadDash(false); setLoadRuns(false); }

    payrollAPI.getMyPayslips().then((res) => {
      const payload = extract(res);
      setMySlips(Array.isArray(payload) ? payload : (payload?.payslips || []));
    }).catch(() => { });
  }, [isPayroll]);

  useEffect(() => { load(); }, [load]);

  const handleRunAction = async (runId, action) => {
    try {
      if (action === 'process') await payrollAPI.processRun(runId, {});
      if (action === 'approve') await payrollAPI.approveRun(runId, {});
      if (action === 'finalize') await payrollAPI.finalizeRun(runId);
      if (action === 'payslips') await payrollAPI.generatePayslips(runId);
      if (action === 'bankfile') { await payrollAPI.generateBankFile(runId, { FileFormat: 'CSV' }); toast.success('Bank file downloading...'); return; }
      toast.success(`Run ${action}d successfully`);
      load();
    } catch (err) { toast.error(err.response?.data?.error?.message || `Failed to ${action}`); }
  };

  const handleCreateRun = async () => {
    setSaving(true);
    try {
      const startDateObj = new Date(runForm.PeriodStartDate);
      const payload = {
        PolicyID: Number(runForm.PolicyID) || 1,
        PeriodYear: startDateObj.getFullYear(),
        PeriodMonth: startDateObj.getMonth() + 1,
        PeriodStartDate: new Date(runForm.PeriodStartDate).toISOString(),
        PeriodEndDate: new Date(runForm.PeriodEndDate).toISOString(),
        CutoffDate: new Date(runForm.CutoffDate || runForm.PeriodEndDate).toISOString(),
        PaymentDate: new Date(runForm.PaymentDate || runForm.PeriodEndDate).toISOString(),
      };
      await payrollAPI.createRun(payload);
      toast.success('Run created');
      setCreateRunModal(false);
      load();
    } catch (err) { toast.error('Failed to create run'); } finally { setSaving(false); }
  };

  const handleResolveException = async (id) => {
    try {
      await payrollAPI.resolveException(id, { resolution: 'Resolved', ResolutionNotes: 'Resolved manually' });
      toast.success('Exception resolved');
      load();
    } catch (err) { toast.error('Failed to resolve'); }
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard' },
    { id: 'myslips', label: 'My Payslips' },
    ...(isPayroll ? [
      { id: 'runs', label: 'Payroll Runs' },
      { id: 'exceptions', label: `Exceptions${exceptions.length ? ` (${exceptions.length})` : ''}` },
      { id: 'config', label: 'System Config' },
    ] : []),
  ];

  const fmt = (v) => v != null ? Number(v).toLocaleString('en-US', { style: 'currency', currency: 'EGP', maximumFractionDigits: 0 }) : '—';
  const dashTotalPay = dashboard?.TotalNetAmount || 0;
  const dashHeadcount = dashboard?.TotalEmployees || 0;
  const dashActiveRuns = dashboard?.ActiveRuns || 0;
  const dashExceptions = dashboard?.OpenExceptions || exceptions.length || 0;
  const chartData = (dashboard?.MonthlySummary || []).map(d => ({ month: d.Month, netPay: d.NetPay, grossPay: d.GrossPay }));

  return (
    <>
      <div className="page-header">
        <h1>Payroll</h1>
        <p>Manage payroll runs, configure policies, and track exceptions</p>
      </div>

      <div className="tabs">
        {TABS.map(({ id, label }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}>
            {label}
          </button>
        ))}
      </div>

      {/* ── Dashboard ── */}
      {tab === 'dashboard' && (
        <>
          {loadDash ? (
            <div className="grid-4"><SkeletonCard /><SkeletonCard /><SkeletonCard /><SkeletonCard /></div>
          ) : (
            <>
              <div className="grid-4" style={{ marginBottom: 24 }}>
                <PayKPI icon={DollarSign} color="var(--green)" label="Total Payroll" value={fmt(dashTotalPay)} sub="This period" />
                <PayKPI icon={Users} color="var(--blue)" label="Employees Paid" value={dashHeadcount} />
                <PayKPI icon={CreditCard} color="var(--gold)" label="Active Runs" value={dashActiveRuns} />
                <PayKPI icon={AlertTriangle} color="var(--red)" label="Open Exceptions" value={dashExceptions} sub="Needs attention" />
              </div>
              {chartData.length > 0 && (
                <div className="card">
                  <div className="card-header"><div className="card-title">Monthly Payroll Trend</div></div>
                  <ResponsiveContainer width="100%" height={220}>
                    <BarChart data={chartData} margin={{ top: 5, right: 5, bottom: 5, left: 5 }}>
                      <XAxis dataKey="month" tick={{ fontSize: 11, fill: 'var(--text-secondary)' }} />
                      <YAxis tick={{ fontSize: 11, fill: 'var(--text-secondary)' }} />
                      <Tooltip contentStyle={{ background: 'var(--bg-elevated)', border: '1px solid var(--border)', borderRadius: 8, fontSize: 12 }} />
                      <Bar dataKey="netPay" fill="var(--gold)" radius={[4, 4, 0, 0]} name="Net Pay" />
                      <Bar dataKey="grossPay" fill="var(--blue-dim)" radius={[4, 4, 0, 0]} name="Gross" />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              )}
            </>
          )}
        </>
      )}

      {/* ── My Payslips ── */}
      {tab === 'myslips' && (
        <div className="table-wrap">
          <table>
            <thead><tr><th>Period</th><th>Gross Pay</th><th>Deductions</th><th>Net Pay</th><th>Status</th><th></th></tr></thead>
            <tbody>
              {myPayslips.map((slip, i) => {
                const runData = slip.PayrollRun || slip;
                const financialData = slip.Entry || slip;
                return (
                  <tr key={slip.PayslipID || i}>
                    <td>{new Date(runData.PeriodStartDate || slip.IssueDate).toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</td>
                    <td style={{ color: 'var(--green)' }}>{fmt(financialData.TotalEarnings || 0)}</td>
                    <td style={{ color: 'var(--red)' }}>{fmt(financialData.TotalDeductions || 0)}</td>
                    <td style={{ color: 'var(--gold)', fontWeight: 700 }}>{fmt(financialData.NetPay || 0)}</td>
                    <td><Badge status={slip.Status || 'Finalized'}>{slip.Status || 'Finalized'}</Badge></td>
                    <td><button className="btn btn-ghost btn-sm" onClick={() => setSlip(slip)}><FileText size={13} /> View</button></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* ── Payroll Runs ── */}
      {tab === 'runs' && isPayroll && (
        <>
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 16 }}>
            <button className="btn btn-primary" onClick={() => setCreateRunModal(true)}><Plus size={16} /> New Run</button>
          </div>
          <div className="table-wrap">
            <table>
              <thead><tr><th>Run ID</th><th>Period</th><th>Status</th><th>Total Net</th><th>Employees</th><th>Actions</th></tr></thead>
              <tbody>
                {runs.map((run, i) => (
                  <tr key={run.PayrollRunID || i}>
                    <td>#{run.PayrollRunID}</td>
                    <td>{new Date(run.PeriodStartDate).toLocaleDateString()} – {new Date(run.PeriodEndDate).toLocaleDateString()}</td>
                    <td><Badge status={run.Status}>{run.Status}</Badge></td>
                    <td style={{ fontWeight: 500 }}>{fmt(run.TotalNetAmount)}</td>
                    <td>{run.TotalEmployees}</td>
                    <td>
                      <div style={{ display: 'flex', gap: 6 }}>
                        {(run.Status === 'Draft' || run.Status === 'Processing') && (
                          <button className="btn btn-primary btn-sm" onClick={() => handleRunAction(run.PayrollRunID, 'process')}><Play size={12} /> {run.Status === 'Processing' ? 'Re-Process' : 'Process'}</button>
                        )}
                        {run.Status === 'PendingApproval' && (
                          <button className="btn btn-success btn-sm" onClick={() => handleRunAction(run.PayrollRunID, 'approve')}><CheckCircle size={12} /> Approve</button>
                        )}
                        {run.Status === 'Approved' && (
                          <button className="btn btn-primary btn-sm" onClick={() => handleRunAction(run.PayrollRunID, 'finalize')}><Zap size={12} /> Finalize</button>
                        )}
                        {run.Status === 'Finalized' && (
                          <button className="btn btn-ghost btn-sm" onClick={() => handleRunAction(run.PayrollRunID, 'payslips')}><FileText size={12} /> Generate Payslips</button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}

      {/* ── Exceptions ── */}
      {tab === 'exceptions' && isPayroll && (
        <div className="table-wrap">
          <table>
            <thead><tr><th>Employee</th><th>Type</th><th>Description</th><th>Severity</th><th>Status</th><th></th></tr></thead>
            <tbody>
              {exceptions.filter(ex => (ex.Status || ex.status || 'Open').toLowerCase() === 'open').map((ex, i) => (
                <tr key={ex.ExceptionID || i}>
                  <td>{ex.Employee?.FullName || '—'}</td>
                  <td>{ex.ExceptionType || '—'}</td>
                  <td style={{ maxWidth: 250 }}><span className="truncate">{ex.Description || '—'}</span></td>
                  <td style={{ color: ex.Severity === 'High' ? 'var(--red)' : 'var(--amber)', fontWeight: 600 }}>{ex.Severity || 'Medium'}</td>
                  <td><Badge status={ex.Status || 'Open'}>{ex.Status || 'Open'}</Badge></td>
                  <td><button className="btn btn-success btn-sm" onClick={() => handleResolveException(ex.ExceptionID)}><CheckCircle size={12} /> Resolve</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ── System Configuration (PR-001 to PR-009) ── */}
      {tab === 'config' && isPayroll && (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: 24 }}>
          {/* PR-001 & PR-004: Global Policies */}
          <div className="card">
            <div className="card-header"><div className="card-title"><Zap size={18} className="text-gold" /> Global Payroll Policies</div></div>
            <div className="card-body">
              <div className="form-group"><label className="form-label">Minimum Wage Cap (EGP)</label><input type="number" className="form-input" defaultValue="6000" /><p style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>PR-004: Prevents net pay from falling below floor.</p></div>
              <div className="form-group"><label className="form-label">Working Days/Month</label><input type="number" className="form-input" defaultValue="22" /><p style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>PR-001: Standard denominator for daily rate.</p></div>
              <button className="btn btn-primary btn-sm" onClick={() => toast.success('Policy saved')}>Save Policies</button>
            </div>
          </div>
          {/* PR-002: Pay Grades */}
          <div className="card">
            <div className="card-header"><div className="card-title"><TrendingUp size={18} className="text-blue" /> Pay Grades & Salary Bands</div></div>
            <div className="table-wrap">
              <table>
                <thead><tr><th>Grade</th><th>Range (EGP)</th><th>Action</th></tr></thead>
                <tbody>
                  <tr><td>Junior (G1)</td><td>15k – 25k</td><td><button className="btn btn-ghost btn-sm">Edit</button></td></tr>
                  <tr><td>Senior (G2)</td><td>30k – 55k</td><td><button className="btn btn-ghost btn-sm">Edit</button></td></tr>
                </tbody>
              </table>
            </div>
            <div className="card-body" style={{ borderTop: '1px solid var(--border)' }}><button className="btn btn-secondary btn-sm w-full"><Plus size={14} /> Define New Band (PR-002)</button></div>
          </div>
          {/* PR-006 & PR-009: Elements */}
          <div className="card">
            <div className="card-header"><div className="card-title"><RefreshCw size={18} className="text-green" /> Rules & Elements</div></div>
            <div className="card-body">
              <div style={{ background: 'var(--bg-elevated)', padding: 12, borderRadius: 8, marginBottom: 12, display: 'flex', justifyContent: 'space-between' }}>
                <div><strong>Standard Overtime</strong><p style={{ fontSize: '0.72rem' }}>PR-006: Applied to hours above threshold.</p></div>
                <Badge status="Active">1.35x Multiplier</Badge>
              </div>
              <div style={{ background: 'var(--bg-elevated)', padding: 12, borderRadius: 8, display: 'flex', justifyContent: 'space-between' }}>
                <div><strong>Housing Allowance</strong><p style={{ fontSize: '0.72rem' }}>PR-009: Recurring credit.</p></div>
                <Badge status="Active">Fixed Element</Badge>
              </div>
              <button className="btn btn-outline btn-sm w-full" style={{ marginTop: 12 }}>Configure Elements (PR-005/007)</button>
            </div>
          </div>
          {/* PR-003: Approval Workflows */}
          <div className="card">
            <div className="card-header"><div className="card-title"><ShieldCheck size={18} className="text-purple" /> Approval Workflows</div></div>
            <div className="card-body">
              <div className="form-group"><label className="form-label">Current Chain</label><select className="form-input"><option>Specialist → Admin → System</option><option>Manager → Finance → CEO</option></select></div>
              <p style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>PR-003: Current workflow requires manual Approval/Finalization.</p>
              <button className="btn btn-primary btn-sm" disabled>Modify Workflow</button>
            </div>
          </div>
        </div>
      )}

      {/* ── Create Run Modal ── */}
      <Modal open={createRunModal} onClose={() => setCreateRunModal(false)} title="Create Payroll Run" footer={<><button className="btn btn-secondary" onClick={() => setCreateRunModal(false)} disabled={saving}>Cancel</button><button className="btn btn-primary" onClick={handleCreateRun} disabled={saving}>{saving ? <InlineSpinner /> : 'Create Run'}</button></>}>
        <div className="form-group"><label className="form-label required">Policy ID</label><input className="form-input" type="number" value={runForm.PolicyID} onChange={e => setRunForm(f => ({ ...f, PolicyID: e.target.value }))} /></div>
        <div className="form-row"><div className="form-group"><label className="form-label required">Start Date</label><input className="form-input" type="date" value={runForm.PeriodStartDate} onChange={e => setRunForm(f => ({ ...f, PeriodStartDate: e.target.value }))} /></div><div className="form-group"><label className="form-label required">End Date</label><input className="form-input" type="date" value={runForm.PeriodEndDate} onChange={e => setRunForm(f => ({ ...f, PeriodEndDate: e.target.value }))} /></div></div>
      </Modal>

      {/* ── Payslip Modal ── */}
      <PayslipModal payslip={selectedSlip} onClose={() => setSlip(null)} />
    </>
  );
}
